create table dirkspzm32.pps_simple_fa (
    sid                      varchar2(2 char) not null enable,
    firma_nr                 number(6, 0) not null enable,
    leitzahl                 number(*, 5) not null enable,
    artikel_id               number(*, 0),
    charge_bez               varchar2(50 char),
    res_id                   number(*, 0),
    login_id                 number(*, 0),
    menge                    number(*, 3),
    text1                    varchar2(100 char),
    text2                    varchar2(100 char),
    text3                    varchar2(100 char),
    soll_betriebsart         varchar2(12 char),
    kunden_nr                varchar2(20 char),
    kenz_lhm_druck           varchar2(1 char) default 'T',
    best_nr_kunde            varchar2(30 char),
    erz_datum                date,
    aend_datum               date,
    abnr                     varchar2(20 char),
    hersteller_kuerzel_liste varchar2(100 char),
    lam_sel1                 varchar2(30 char),
    lam_sel2                 varchar2(30 char),
    lam_sel3                 varchar2(30 char),
    lam_sel4                 varchar2(30 char),
    lam_sel5                 varchar2(30 char),
    lam_sel6                 varchar2(30 char),
    lam_sel7                 varchar2(30 char),
    lam_sel8                 varchar2(30 char),
    lam_sel9                 varchar2(30 char),
    lam_sel10                varchar2(30 char),
    lohn_arbeit              varchar2(1 char) default 'F',
    adress_id                number(*, 0),
    prod_params              varchar2(4000 char),
    created_date             date default sysdate not null enable,
    created_login_id         number(*, 0) default - 1 not null enable,
    last_change_date         date,
    last_change_login_id     number(*, 0),
    seq_nr                   number,
    lead_leitzahl            number,
    primaer_leitzahl         number
);

alter table dirkspzm32.pps_simple_fa
    add constraint chk_pps_simple_fa_kz_druck
        check ( kenz_lhm_druck in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.pps_simple_fa
    add constraint pk_pps_simple_fa
        primary key ( leitzahl,
                      firma_nr,
                      sid )
            using index enable;


